/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * Student implementation.
 */

#include <assert.h>
#include <pthread.h>
#include <signal.h>

#include "csapp.h"

/* Number of prethreaded worker threads and shared buffer size */
#define NTHREADS  8
#define SBUFSIZE  64

/*
 * Shared bounded buffer for prethreading.
 * Uses pthread mutex and condition variables (no semaphores).
 */
typedef struct {
	int              *buf;       /* Array of connected file descriptors */
	int               n;         /* Capacity */
	int               front;     /* Index of first item */
	int               rear;      /* Index of last item */
	int               count;     /* Current number of items */
	pthread_mutex_t   mutex;
	pthread_cond_t    not_empty;
	pthread_cond_t    not_full;
} sbuf_t;

static void	sbuf_init(sbuf_t *sp, int n);
static void	sbuf_insert(sbuf_t *sp, int item);
static int	sbuf_remove(sbuf_t *sp);

static void    *thread(void *vargp);
static void	handle_request(int connfd, struct sockaddr_in *clientaddr);

static void	client_error(int fd, const char *cause, int err_num,
		    const char *short_msg, const char *long_msg);
static char    *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int	parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);

/* Global log file, protected by log_mutex */
static FILE           *log_file;
static pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Global shared buffer */
static sbuf_t sbuf;

/*
 * Requires:
 *   argv[1] is a valid port number string.
 *
 * Effects:
 *   Opens a listening socket, prethreads NTHREADS worker threads, then
 *   accepts client connections in a loop, inserting each connected
 *   descriptor into the shared buffer for a worker thread to handle.
 */
int
main(int argc, char **argv)
{
	int               listenfd;
	int               connfd;
	socklen_t         clientlen;
	struct sockaddr_in clientaddr;
	pthread_t         tids[NTHREADS];
	int               i;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	/* Ignore SIGPIPE so that broken connections don't crash us. */
	Signal(SIGPIPE, SIG_IGN);

	/* Open the log file once at startup. */
	log_file = fopen("proxy.log", "a");
	if (log_file == NULL) {
		fprintf(stderr, "Error opening proxy.log\n");
		exit(1);
	}

	/* Initialize the shared buffer. */
	sbuf_init(&sbuf, SBUFSIZE);

	/* Prethread worker threads. */
	for (i = 0; i < NTHREADS; i++)
		Pthread_create(&tids[i], NULL, thread, NULL);

	/* Open listening socket. */
	listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "Error opening listen socket on port %s\n", argv[1]);
		exit(1);
	}

	/* Accept connections and dispatch to workers. */
	while (1) {
		clientlen = sizeof(clientaddr);
		connfd = accept(listenfd, (SA *)&clientaddr, &clientlen);
		if (connfd < 0)
			continue;
		/*
		 * Allocate a struct to pass both connfd and clientaddr to
		 * sbuf. We pass connfd via sbuf and handle clientaddr lookup
		 * differently.
		 *
		 * Since we need the client address in the worker thread,
		 * allocate heap memory for it.
		 */
		int *pconnfd = Malloc(sizeof(int));
		*pconnfd = connfd;
		/*
		 * We also need to pass clientaddr. Use a combined struct.
		 */
		struct conn_info {
			int               connfd;
			struct sockaddr_in clientaddr;
		};
		/* This approach won't work well with sbuf holding only int.
		 * Instead, let's store connfd in sbuf and re-fetch client
		 * addr from the socket via getpeername in the worker. */
		free(pconnfd);
		sbuf_insert(&sbuf, connfd);
	}

	/* Return success. */
	return (0);
}

/*
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   Worker thread: repeatedly removes a connected descriptor from the
 *   shared buffer and handles the HTTP request.
 */
static void *
thread(void *vargp)
{
	(void)vargp;
	Pthread_detach(pthread_self());

	while (1) {
		int connfd = sbuf_remove(&sbuf);

		/* Get client address via getpeername. */
		struct sockaddr_in clientaddr;
		socklen_t clientlen = sizeof(clientaddr);
		if (getpeername(connfd, (SA *)&clientaddr, &clientlen) < 0)
			memset(&clientaddr, 0, sizeof(clientaddr));

		handle_request(connfd, &clientaddr);
		close(connfd);
	}

	return (NULL);
}

/*
 * Requires:
 *   connfd is a connected socket to the client.
 *   clientaddr points to the client's socket address.
 *
 * Effects:
 *   Reads an HTTP GET request from the client, forwards it to the end
 *   server, relays the response back to the client, and writes a log
 *   entry to proxy.log.
 */
static void
handle_request(int connfd, struct sockaddr_in *clientaddr)
{
	rio_t    client_rio;
	char     buf[MAXLINE];
	char     method[MAXLINE], uri[MAXLINE], version[MAXLINE];
	char    *hostname = NULL, *port = NULL, *pathname = NULL;
	int      serverfd = -1;
	long     total_bytes = 0;

	rio_readinitb(&client_rio, connfd);

	/* Read the request line. */
	ssize_t n = rio_readlineb(&client_rio, buf, MAXLINE);
	if (n <= 0)
		return;

	/* Parse method, URI, and version. */
	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
		client_error(connfd, buf, 400, "Bad Request",
		    "Could not parse the request line");
		return;
	}

	/* Only support GET. */
	if (strcasecmp(method, "GET") != 0) {
		client_error(connfd, method, 501, "Not Implemented",
		    "Proxy only supports GET method");
		return;
	}

	/* Parse the URI. */
	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
		client_error(connfd, uri, 400, "Bad Request",
		    "Could not parse the URI");
		return;
	}

	/* Build the request to forward to the server. */
	/* Start with the request line using path only, HTTP/1.0. */
	char request_buf[MAXLINE * 4];
	int  request_len = 0;

	request_len += snprintf(request_buf + request_len,
	    sizeof(request_buf) - request_len,
	    "GET %s HTTP/1.0\r\n", pathname);

	/* Add Host header. */
	request_len += snprintf(request_buf + request_len,
	    sizeof(request_buf) - request_len,
	    "Host: %s\r\n", hostname);

	/* Read and forward remaining headers from client. */
	while (1) {
		n = rio_readlineb(&client_rio, buf, MAXLINE);
		if (n <= 0)
			break;

		/* End of headers. */
		if (strcmp(buf, "\r\n") == 0 || strcmp(buf, "\n") == 0)
			break;

		/* Strip Connection, Keep-Alive, Proxy-Connection headers. */
		if (strncasecmp(buf, "Connection:", 11) == 0 ||
		    strncasecmp(buf, "Keep-Alive:", 11) == 0 ||
		    strncasecmp(buf, "Proxy-Connection:", 17) == 0 ||
		    strncasecmp(buf, "Host:", 5) == 0)
			continue;

		/* Forward other headers if there is space. */
		if (request_len + (int)strlen(buf) + 2 <
		    (int)sizeof(request_buf) - 32) {
			request_len += snprintf(request_buf + request_len,
			    sizeof(request_buf) - request_len, "%s", buf);
		}
	}

	/* Add Connection: close header and blank line. */
	request_len += snprintf(request_buf + request_len,
	    sizeof(request_buf) - request_len,
	    "Connection: close\r\n\r\n");

	/* Connect to the end server. */
	serverfd = open_clientfd(hostname, port);
	if (serverfd < 0) {
		client_error(connfd, hostname, 404, "Not Found",
		    "Could not connect to the end server");
		goto cleanup;
	}

	/* Send the request to the server. */
	if (rio_writen(serverfd, request_buf, request_len) < 0)
		goto cleanup;

	/* Relay the server response back to the client. */
	char  resp_buf[MAXBUF];
	ssize_t nread;
	while ((nread = rio_readn(serverfd, resp_buf, sizeof(resp_buf))) > 0) {
		if (rio_writen(connfd, resp_buf, nread) < 0)
			break;
		total_bytes += nread;
	}
	/* If nread == 0, server closed; any partial write is fine. */

	/* Write log entry. */
	{
		char *log_entry = create_log_entry(clientaddr, uri,
		    (int)total_bytes);
		pthread_mutex_lock(&log_mutex);
		fprintf(log_file, "%s\n", log_entry);
		fflush(log_file);
		pthread_mutex_unlock(&log_mutex);
		free(log_entry);
	}

cleanup:
	if (serverfd >= 0)
		close(serverfd);
	if (hostname != NULL)
		free(hostname);
	if (port != NULL)
		free(port);
	if (pathname != NULL)
		free(pathname);
}

/* =========================================================================
 * Shared buffer (sbuf) implementation using mutex + condition variables
 * ========================================================================= */

/*
 * Requires:
 *   n > 0.
 *
 * Effects:
 *   Initializes the shared buffer sp with capacity n.
 */
static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf   = Calloc(n, sizeof(int));
	sp->n     = n;
	sp->front = 0;
	sp->rear  = 0;
	sp->count = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->not_empty, NULL);
	pthread_cond_init(&sp->not_full, NULL);
}

/*
 * Requires:
 *   sp has been initialized with sbuf_init.
 *
 * Effects:
 *   Inserts item into the shared buffer, blocking if the buffer is full.
 */
static void
sbuf_insert(sbuf_t *sp, int item)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->count == sp->n)
		pthread_cond_wait(&sp->not_full, &sp->mutex);
	sp->buf[sp->rear] = item;
	sp->rear = (sp->rear + 1) % sp->n;
	sp->count++;
	pthread_cond_signal(&sp->not_empty);
	pthread_mutex_unlock(&sp->mutex);
}

/*
 * Requires:
 *   sp has been initialized with sbuf_init.
 *
 * Effects:
 *   Removes and returns an item from the shared buffer, blocking if empty.
 */
static int
sbuf_remove(sbuf_t *sp)
{
	int item;
	pthread_mutex_lock(&sp->mutex);
	while (sp->count == 0)
		pthread_cond_wait(&sp->not_empty, &sp->mutex);
	item = sp->buf[sp->front];
	sp->front = (sp->front + 1) % sp->n;
	sp->count--;
	pthread_cond_signal(&sp->not_full);
	pthread_mutex_unlock(&sp->mutex);
	return (item);
}

/*
 * Requires:
 *   The parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
 *   host name, port, and path name.  Create strings containing the host name,
 *   port, and path name, and return them through the parameters "hostnamep",
 *   "portp", "pathnamep", respectively.  (The caller must free the memory
 *   storing these strings.)  Return -1 if there are any problems and 0
 *   otherwise.
 */
static int
parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
{
	const char *pathname_begin, *port_begin, *port_end;

	if (strncasecmp(uri, "http://", 7) != 0)
		return (-1);

	/* Extract the host name. */
	const char *host_begin = uri + 7;
	const char *host_end = strpbrk(host_begin, ":/ \r\n");
	if (host_end == NULL)
		host_end = host_begin + strlen(host_begin);
	int len = host_end - host_begin;
	char *hostname = Malloc(len + 1);
	strncpy(hostname, host_begin, len);
	hostname[len] = '\0';
	*hostnamep = hostname;

	/* Look for a port number.  If none is found, use port 80. */
	if (*host_end == ':') {
		port_begin = host_end + 1;
		port_end = strpbrk(port_begin, "/ \r\n");
		if (port_end == NULL)
			port_end = port_begin + strlen(port_begin);
		len = port_end - port_begin;
	} else {
		port_begin = "80";
		port_end = host_end;
		len = 2;
	}
	char *port = Malloc(len + 1);
	strncpy(port, port_begin, len);
	port[len] = '\0';
	*portp = port;

	/* Extract the path. */
	if (*port_end == '/') {
		pathname_begin = port_end;
		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
		if (pathname_end == NULL)
			pathname_end = pathname_begin + strlen(pathname_begin);
		len = pathname_end - pathname_begin;
	} else {
		pathname_begin = "/";
		len = 1;
	}
	char *pathname = Malloc(len + 1);
	strncpy(pathname, pathname_begin, len);
	pathname[len] = '\0';
	*pathnamep = pathname;

	return (0);
}

/*
 * Requires:
 *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
 *   parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Returns a string containing a properly formatted log entry.  This log
 *   entry is based upon the socket address of the requesting client
 *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
 *   the response from the server ("size").
 */
static char *
create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
{
	struct tm result;

	/*
	 * Create a large enough array of characters to store a log entry.
	 * Although the length of the URI can exceed MAXLINE, the combined
	 * lengths of the other fields and separators cannot.
	 */
	const size_t log_maxlen = MAXLINE + strlen(uri);
	char *const log_str = Malloc(log_maxlen + 1);

	/* Get a formatted time string. */
	time_t now = time(NULL);
	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
	    localtime_r(&now, &result));

	/*
	 * Convert the IP address in network byte order to dotted decimal
	 * form.
	 */
	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
	    INET_ADDRSTRLEN);
	log_strlen += strlen(&log_str[log_strlen]);

	/*
	 * Assert that the time and IP address fields occupy less than half of
	 * the space that is reserved for the non-URI fields.
	 */
	assert(log_strlen < MAXLINE / 2);

	/*
	 * Add the URI and response size onto the end of the log entry.
	 */
	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
	    size);

	return (log_str);
}

/*
 * Requires:
 *   The parameter "fd" must be an open socket that is connected to the client.
 *   The parameters "cause", "short_msg", and "long_msg" must point to properly
 *   NUL-terminated strings that describe the reason why the HTTP transaction
 *   failed.  The string "short_msg" may not exceed 32 characters in length,
 *   and the string "long_msg" may not exceed 80 characters in length.
 *
 * Effects:
 *   Constructs an HTML page describing the reason why the HTTP transaction
 *   failed, and writes an HTTP/1.0 response containing that page as the
 *   content.  The cause appearing in the HTML page is truncated if the
 *   string "cause" exceeds 2048 characters in length.
 */
static void
client_error(int fd, const char *cause, int err_num, const char *short_msg,
    const char *long_msg)
{
	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];

	assert(strlen(short_msg) <= 32);
	assert(strlen(long_msg) <= 80);
	/* Ensure that "body" is much larger than "truncated_cause". */
	assert(sizeof(truncated_cause) < MAXBUF / 2);

	/*
	 * Create a truncated "cause" string so that the response body will not
	 * exceed MAXBUF.
	 */
	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
	truncated_cause[sizeof(truncated_cause) - 1] = '\0';

	/* Build the HTTP response body. */
	snprintf(body, MAXBUF,
	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
	    "%d: %s\r\n"
	    "<p>%s: %s\r\n"
	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
	    err_num, short_msg, long_msg, truncated_cause);

	/* Build the HTTP response headers. */
	snprintf(headers, MAXBUF,
	    "HTTP/1.0 %d %s\r\n"
	    "Content-type: text/html\r\n"
	    "Content-length: %d\r\n"
	    "\r\n",
	    err_num, short_msg, (int)strlen(body));

	/* Write the HTTP response. */
	if (rio_writen(fd, headers, strlen(headers)) != -1)
		rio_writen(fd, body, strlen(body));
}

/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * Student implementation.
 */

#include <assert.h>
#include <pthread.h>
#include <signal.h>

#include "csapp.h"

/* Number of prethreaded worker threads and shared buffer capacity */
#define NTHREADS  8
#define SBUFSIZE  64

/*
 * Shared bounded buffer for prethreading.
 * Uses pthread mutex and condition variables (no semaphores per spec).
 */
typedef struct {
	int            *buf;       /* Array of connected file descriptors */
	int             n;         /* Capacity */
	int             front;     /* Index of first item */
	int             rear;      /* Index past last item */
	int             count;     /* Current number of items */
	pthread_mutex_t mutex;
	pthread_cond_t  not_empty;
	pthread_cond_t  not_full;
} sbuf_t;

/* Forward declarations */
static void	sbuf_init(sbuf_t *sp, int n);
static void	sbuf_insert(sbuf_t *sp, int item);
static int	sbuf_remove(sbuf_t *sp);

static void    *thread(void *vargp);
static void	handle_request(int connfd, struct sockaddr_in *clientaddr);

static void	client_error(int fd, const char *cause, int err_num,
		    const char *short_msg, const char *long_msg);
static char    *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int	parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);

/* Global log file, protected by log_mutex */
static FILE           *log_file;
static pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Global shared buffer of connected descriptors */
static sbuf_t sbuf;

/*
 * Requires:
 *   argv[1] is a valid port number string in the range 18000-18200.
 *
 * Effects:
 *   Opens a listening socket on the given port, starts NTHREADS worker
 *   threads, then loops accepting connections and inserting them into the
 *   shared buffer for workers to handle.
 */
int
main(int argc, char **argv)
{
	int                listenfd, connfd;
	socklen_t          clientlen;
	struct sockaddr_in clientaddr;
	pthread_t          tids[NTHREADS];
	int                i;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	/* Ignore SIGPIPE so broken connections don't crash the proxy. */
	Signal(SIGPIPE, SIG_IGN);

	/* Open the log file once at startup (append mode). */
	log_file = fopen("proxy.log", "a");
	if (log_file == NULL) {
		fprintf(stderr, "Error opening proxy.log\n");
		exit(1);
	}

	/* Initialize the shared bounded buffer. */
	sbuf_init(&sbuf, SBUFSIZE);

	/* Prethread NTHREADS worker threads. */
	for (i = 0; i < NTHREADS; i++)
		Pthread_create(&tids[i], NULL, thread, NULL);

	/* Open the listening socket. */
	listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "Error opening listen socket on port %s\n",
		    argv[1]);
		exit(1);
	}

	/* Accept connections and dispatch to worker threads via sbuf. */
	while (1) {
		clientlen = sizeof(clientaddr);
		connfd = accept(listenfd, (SA *)&clientaddr, &clientlen);
		if (connfd < 0)
			continue;
		sbuf_insert(&sbuf, connfd);
	}

	/* Return success. */
	return (0);
}

/*
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   Worker thread routine.  Detaches itself, then repeatedly removes a
 *   connected descriptor from the shared buffer and services the request.
 */
static void *
thread(void *vargp)
{
	(void)vargp;
	Pthread_detach(pthread_self());

	while (1) {
		int                connfd = sbuf_remove(&sbuf);
		struct sockaddr_in clientaddr;
		socklen_t          clientlen = sizeof(clientaddr);

		/* Recover the client address from the connected socket. */
		if (getpeername(connfd, (SA *)&clientaddr, &clientlen) < 0)
			memset(&clientaddr, 0, sizeof(clientaddr));

		handle_request(connfd, &clientaddr);
		close(connfd);
	}

	return (NULL);
}

/*
 * Requires:
 *   connfd is an open, connected socket to the browser client.
 *   clientaddr points to the client's socket address.
 *
 * Effects:
 *   Reads one HTTP GET request from the client, connects to the end
 *   server, forwards the (rewritten) request, relays the response back
 *   to the client, and appends a log entry to proxy.log.  On any
 *   error before the response has started, sends an HTTP error page to
 *   the client.
 */
static void
handle_request(int connfd, struct sockaddr_in *clientaddr)
{
	rio_t  client_rio;
	char   buf[MAXLINE];
	char   method[MAXLINE], uri[MAXLINE], version[MAXLINE];
	char  *hostname = NULL, *port = NULL, *pathname = NULL;
	int    serverfd = -1;
	long   total_bytes = 0;

	rio_readinitb(&client_rio, connfd);

	/* Read the HTTP request line. */
	ssize_t n = rio_readlineb(&client_rio, buf, MAXLINE);
	if (n <= 0)
		goto cleanup;

	/* Parse "METHOD URI VERSION". */
	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
		client_error(connfd, buf, 400, "Bad Request",
		    "Could not parse the request line");
		goto cleanup;
	}

	/* Only support the GET method. */
	if (strcasecmp(method, "GET") != 0) {
		client_error(connfd, method, 501, "Not Implemented",
		    "Proxy only supports GET method");
		goto cleanup;
	}

	/* Validate and parse the URI into hostname, port, and pathname. */
	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
		client_error(connfd, uri, 400, "Bad Request",
		    "Could not parse the URI");
		goto cleanup;
	}

	/*
	 * Build the forwarded request.  Rewrite the start line to use the
	 * path only (not the full URI) and downgrade to HTTP/1.0.
	 */
	char  reqbuf[MAXLINE * 8];
	int   reqlen = 0;

	reqlen += snprintf(reqbuf + reqlen, sizeof(reqbuf) - reqlen,
	    "GET %s HTTP/1.0\r\n", pathname);
	reqlen += snprintf(reqbuf + reqlen, sizeof(reqbuf) - reqlen,
	    "Host: %s\r\n", hostname);

	/*
	 * Copy headers from the client request, stripping Connection,
	 * Keep-Alive, Proxy-Connection, and Host (we set Host ourselves).
	 */
	while (1) {
		n = rio_readlineb(&client_rio, buf, MAXLINE);
		if (n <= 0)
			break;
		/* Blank line marks end of headers. */
		if (strcmp(buf, "\r\n") == 0 || strcmp(buf, "\n") == 0)
			break;

		if (strncasecmp(buf, "Connection:",       11) == 0 ||
		    strncasecmp(buf, "Keep-Alive:",        11) == 0 ||
		    strncasecmp(buf, "Proxy-Connection:",  17) == 0 ||
		    strncasecmp(buf, "Host:",               5) == 0)
			continue;

		/* Append header if it fits. */
		int hlen = (int)strlen(buf);
		if (reqlen + hlen < (int)sizeof(reqbuf) - 32)
			reqlen += snprintf(reqbuf + reqlen,
			    sizeof(reqbuf) - reqlen, "%s", buf);
	}

	/* Terminate with Connection: close and blank line. */
	reqlen += snprintf(reqbuf + reqlen, sizeof(reqbuf) - reqlen,
	    "Connection: close\r\n\r\n");

	/* Connect to the end server. */
	serverfd = open_clientfd(hostname, port);
	if (serverfd < 0) {
		client_error(connfd, hostname, 404, "Not Found",
		    "Could not connect to the end server");
		goto cleanup;
	}

	/* Forward the rewritten request to the server. */
	if (rio_writen(serverfd, reqbuf, reqlen) < 0)
		goto cleanup;

	/*
	 * Relay the server's response back to the client, counting the total
	 * bytes so we can log the size.
	 */
	char    respbuf[MAXBUF];
	ssize_t nread;
	while ((nread = rio_readn(serverfd, respbuf, sizeof(respbuf))) > 0) {
		if (rio_writen(connfd, respbuf, nread) < 0)
			break;
		total_bytes += nread;
	}

	/* Write a log entry (only for transactions that got a response). */
	{
		char *log_entry = create_log_entry(clientaddr, uri,
		    (int)total_bytes);
		pthread_mutex_lock(&log_mutex);
		fprintf(log_file, "%s\n", log_entry);
		fflush(log_file);
		pthread_mutex_unlock(&log_mutex);
		free(log_entry);
	}

cleanup:
	if (serverfd >= 0)
		close(serverfd);
	free(hostname);
	free(port);
	free(pathname);
}

